<template>
  <view class="service-chat">
    <view class="chat-header">
      <text class="chat-title">在线客服</text>
      <text class="chat-subtitle">工作时间：8:00-22:00</text>
    </view>

    <scroll-view class="chat-messages" scroll-y>
      <view class="message-item system">
        <view class="message-content">
          <text class="message-text">您好！欢迎来到代取s客服中心，有什么可以帮助您的吗？</text>
        </view>
        <text class="message-time">{{ currentTime }}</text>
      </view>

      <view class="quick-actions">
        <text class="quick-title">常见问题：</text>
        <view class="quick-buttons">
          <button class="quick-btn" @click="sendQuickMessage('订单问题')">订单问题</button>
          <button class="quick-btn" @click="sendQuickMessage('支付问题')">支付问题</button>
          <button class="quick-btn" @click="sendQuickMessage('配送问题')">配送问题</button>
          <button class="quick-btn" @click="sendQuickMessage('退款问题')">退款问题</button>
        </view>
      </view>
    </scroll-view>

    <view class="chat-input-area">
      <view class="input-row">
        <button class="kf-btn" open-type="contact">
          <text class="kf-icon">💬</text>
          <text class="kf-text">联系人工客服</text>
        </button>
        <button class="phone-btn" @click="callPhone">
          <text class="phone-icon">📞</text>
          <text class="phone-text">电话客服</text>
        </button>
      </view>
    </view>
  </view>
</template>

<script setup>
import { ref } from 'vue'
import { onLoad } from '@dcloudio/uni-app'

const currentTime = ref('')

const updateTime = () => {
  const now = new Date()
  currentTime.value = now.toLocaleString('zh-CN', {
    hour: '2-digit',
    minute: '2-digit'
  })
}

const sendQuickMessage = (message) => {
  uni.showToast({
    title: `已发送：${message}`,
    icon: 'none'
  })
  // 这里可以集成到微信客服系统
}

const callPhone = () => {
  uni.makePhoneCall({
    phoneNumber: '18608945191',
    success: () => {
      console.log('拨打电话成功')
    },
    fail: (err) => {
      console.error('拨打电话失败', err)
      uni.showToast({
        title: '拨打电话失败',
        icon: 'none'
      })
    }
  })
}

onLoad(() => {
  updateTime()
  setInterval(updateTime, 60000) // 每分钟更新时间
})
</script>

